36		/**
37		 * 비속어 관리 메인 화면
38		 */
39		@RequestMapping("/bword/bWordMng.do")
40		public String bWordMng(HttpServletRequest request, HttpServletResponse response) throws Exception {
41			return "sia/web/bword/bWordMng";
42		}
