44		/**
45		 * 비속어 목록 조회
46		 */
47		@RequestMapping("/bword/selectBWordList.json")
48		public ModelAndView bWordMngList(BWordVO bWordVO) throws Exception {
49	
50			// 페이징 계산
51			int nowPage = bWordVO.getNewPage() > 0 ? bWordVO.getNewPage() : 1;
52			int pageSize = bWordVO.getPageSize() > 0 ? bWordVO.getPageSize() : 10;
53	
54			int startRowNum = (nowPage - 1) * pageSize + 1;
55			int endRowNum = nowPage * pageSize;
56	
57			bWordVO.setStartRowNum(startRowNum);
58			bWordVO.setEndRowNum(endRowNum);
59			bWordVO.setNewPage(nowPage);
60			bWordVO.setPageSize(pageSize);
61	
62			List<BWordVO> resultData = bWordMngService.selectBWordList(bWordVO);
63	
64			if(!resultData.isEmpty()){
65				mv.addObject("maxPage", resultData.get(0).getTotCnt());
66			}else{
67				mv.addObject("maxPage", 0);
68			}
69		    mv.addObject("newPage"		, bWordVO.getNewPage());
70		    mv.addObject("pageSize"		, bWordVO.getPageSize());
71		    mv.addObject("resultList"	, resultData);
72			return success();
73		}
74	
75		/**
76		 * 비속어 등록/수정
77		 */
78		@RequestMapping("/bword/insertBWord.json")
79		public ModelAndView insertBWord(BWordVO bWordVO, HttpServletRequest request) throws Exception {
80	
81			// 중복 체크
82			List<BWordVO> dupList = bWordMngService.bWordDupChk(bWordVO);
83			if(!dupList.isEmpty()){
84				mv.addObject("result", "DUP");
85				return success();
86			}
87	
88			bWordVO.setUserId((String) request.getSession().getAttribute("userId"));
89			bWordMngService.insertBWord(bWordVO);
90			mv.addObject("result", "OK");
91			return success();
92		}
