115		@RequestMapping("/bword/getBWordCacheEntries.json")
116		public ModelAndView getBWordCacheEntries() throws Exception {
117			List<Map<String, Object>> cacheEntries = new ArrayList<Map<String, Object>>();
118	
119			if (cacheManager instanceof EhCacheCacheManager) {
120				EhCacheCacheManager ehCacheCacheManager = (EhCacheCacheManager) cacheManager;
121				net.sf.ehcache.Cache cache = ehCacheCacheManager.getCacheManager().getCache("bwordCache");
122	
123				if (cache != null) {
124					List keys = cache.getKeys();
125	
126					for (Object key : keys) {
127						Element element = cache.get(key);
128						if (element == null) {
129	
130							continue;
131						}
132	
133						Map<String, Object> entry = new HashMap<String, Object>();
134						entry.put("key", key);
135						entry.put("value", element.getObjectValue());
136						entry.put("hitCount", element.getHitCount());
137						entry.put("creationTime", element.getCreationTime());
138						entry.put("lastAccessTime", element.getLastAccessTime());
139						cacheEntries.add(entry);
140					}
141				}
142			}
143	
144			mv.addObject("cacheSize", cacheEntries.size());
145			mv.addObject("cacheEntries", cacheEntries);
146			return success();
147		}
148	
149	}
